// Find And Study main-agency seal + signature image (500x331 PNG), inlined as a
// base64 `data:` URL. It is embedded directly in source (rather than fetched at
// runtime or read from disk) so the final signed-contract PDF render has ZERO
// runtime, external-network or filesystem dependency: it resolves identically
// under tsx in dev and the esbuild CJS bundle in prod, and can never fail to
// load (no fetch to time out, no path to misresolve). Source asset:
// https://www.findandstudy.com/wp-content/uploads/2026/06/kaseimza.png
//
// This is injected ONLY into the final, post-signature PDF render
// (ensureSignedContractPdf) — never into the preview / signing-screen render, so
// the seal appears only after the sub-agent has signed.
export const MAIN_AGENCY_SIGNATURE_DATA_URL =
  "data:image/png;base64,";
